    /// <summary>
    /// Secure binding factory that creates HIPAA-compliant WCF bindings
    /// using strong encryption algorithms (AES-256, SHA-256, RSA-OAEP).
    /// 
    /// Security review notes:
    /// - Uses SecurityAlgorithmSuite.Basic256Sha256 which provides:
    ///   * AES-256-CBC for symmetric encryption (not weak DES/3DES/RC4)
    ///   * SHA-256 for digest/signature (not weak SHA-1/MD5)
    ///   * RSA-OAEP for key wrap (not weak RSA v1.5)
    /// - Enforces mutual certificate authentication (message-level security)
    /// - Requires signed and encrypted message parts
    /// - TLS 1.2 transport layer for additional defense in depth
    /// </summary>
    public static class SecureBindingFactory
    {
        /// <summary>
        /// Creates a custom binding with strong WS-Security encryption for HIPAA compliance.
        /// Uses AES-256 with SHA-256 (Basic256Sha256 suite) — avoids weak algorithms
        /// such as DES, 3DES, RC4, SHA-1, and RSA v1.5 key transport.
        /// </summary>
        public static CustomBinding CreateHipaaCompliantBinding()
        {
            // Use AsymmetricSecurityBindingElement for mutual certificate authentication
            var securityElement = SecurityBindingElement.CreateMutualCertificateBindingElement(
                MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

            // SECURE: Use Basic256Sha256 which provides:
            //   - AES-256-CBC for symmetric encryption
            //   - HMAC-SHA256 for message authentication
            //   - SHA-256 for digest
            //   - RSA-OAEP for asymmetric key wrap
            // This avoids weak algorithms (DES, 3DES, RC4, SHA-1, RSA v1.5)
            securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

            // Require encryption and signing of all message parts
            securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;
            securityElement.IncludeTimestamp = true;
            securityElement.SetKeyDerivation(true);

            // Protect against replay attacks
            securityElement.LocalClientSettings.DetectReplays = true;
            securityElement.LocalClientSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            securityElement.LocalClientSettings.ReplayWindow = TimeSpan.FromMinutes(5);
            securityElement.LocalClientSettings.TimestampValidityDuration = TimeSpan.FromMinutes(5);

            securityElement.LocalServiceSettings.DetectReplays = true;
            securityElement.LocalServiceSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            securityElement.LocalServiceSettings.ReplayWindow = TimeSpan.FromMinutes(5);
            securityElement.LocalServiceSettings.TimestampValidityDuration = TimeSpan.FromMinutes(5);

            // Message encoding — use SOAP 1.2 with MTOM for efficient binary data
            var textEncoding = new TextMessageEncodingBindingElement
            {
                MessageVersion = MessageVersion.Soap12WSAddressing10,
                WriteEncoding = System.Text.Encoding.UTF8
            };

            // HTTPS transport for defense in depth
            var httpsTransport = new HttpsTransportBindingElement
            {
                RequireClientCertificate = true,
                MaxReceivedMessageSize = 10 * 1024 * 1024, // 10 MB
                MaxBufferSize = 10 * 1024 * 1024
            };

            var binding = new CustomBinding(securityElement, textEncoding, httpsTransport);
            binding.ReceiveTimeout = TimeSpan.FromMinutes(10);
            binding.SendTimeout = TimeSpan.FromMinutes(10);

            return binding;
        }

        /// <summary>
        /// Alternative: WSHttpBinding with strong security settings.
        /// Also uses Basic256Sha256 to avoid weak encryption.
        /// </summary>
        public static WSHttpBinding CreateSecureWsHttpBinding()
        {
            var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
            {
                MaxReceivedMessageSize = 10 * 1024 * 1024,
                ReaderQuotas =
                {
                    MaxDepth = 64,
                    MaxStringContentLength = 1024 * 1024,
                    MaxArrayLength = 1024 * 1024,
                    MaxBytesPerRead = 4096,
                    MaxNameTableCharCount = 16384
                }
            };

            binding.Security.Mode = SecurityMode.TransportWithMessageCredential;
            binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;

            // SECURE: Use Basic256Sha256 — AES-256 + SHA-256
            // Avoids weak suites like Basic128, Basic192, TripleDes, etc.
            binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;
            binding.Security.Message.NegotiateServiceCredential = false;
            binding.Security.Message.EstablishSecurityContext = true;

            binding.Security.Transport.ClientCredentialType = HttpClientCredentialType.Certificate;

            return binding;
        }
    }

    /// <summary>
    /// Service host configuration for the healthcare records service.
    /// </summary>
    public class HealthcareServiceHost
    {
        private ServiceHost _serviceHost;

        public void Start(string baseAddress, string certThumbprint)
        {
            var uri = new Uri(baseAddress);
            _serviceHost = new ServiceHost(typeof(HealthcareRecordsServiceImpl), uri);

            // Use the HIPAA-compliant custom binding
            var binding = SecureBindingFactory.CreateHipaaCompliantBinding();

            var endpoint = _serviceHost.AddServiceEndpoint(
                typeof(IHealthcareRecordsService),
                binding,
                "HealthcareRecords");

            // Configure service credentials with X.509 certificates
            ConfigureServiceCredentials(certThumbprint);

            // Configure metadata (only over HTTPS in production)
            ConfigureMetadata(uri);

            // Configure service throttling
            ConfigureThrottling();

            _serviceHost.Open();
            Console.WriteLine($"Healthcare Records Service started at {baseAddress}");
        }

        public void Stop()
        {
            if (_serviceHost != null &&
                _serviceHost.State != CommunicationState.Closed &&
                _serviceHost.State != CommunicationState.Faulted)
            {
                _serviceHost.Close();
                Console.WriteLine("Healthcare Records Service stopped.");
            }
        }

        private void ConfigureServiceCredentials(string certThumbprint)
        {
            var credentials = _serviceHost.Credentials;

            // Service certificate for message encryption/signing
            credentials.ServiceCertificate.SetCertificate(
                StoreLocation.LocalMachine,
                StoreName.My,
                X509FindType.FindByThumbprint,
                certThumbprint);

            // Client certificate authentication and validation
            credentials.ClientCertificate.Authentication.CertificateValidationMode =
                System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
            credentials.ClientCertificate.Authentication.RevocationMode =
                X509RevocationMode.Online;
            credentials.ClientCertificate.Authentication.TrustedStoreLocation =
                StoreLocation.LocalMachine;
        }

        private void ConfigureMetadata(Uri baseUri)
        {
            var metadataBehavior = _serviceHost.Description.Behaviors
                .Find<ServiceMetadataBehavior>();

            if (metadataBehavior == null)
            {
                metadataBehavior = new ServiceMetadataBehavior();
                _serviceHost.Description.Behaviors.Add(metadataBehavior);
            }

            // Only expose metadata over HTTPS
            metadataBehavior.HttpGetEnabled = false;
            metadataBehavior.HttpsGetEnabled = true;
            metadataBehavior.HttpsGetUrl = new Uri(baseUri, "mex");
        }

        private void ConfigureThrottling()
        {
            var throttle = _serviceHost.Description.Behaviors
                .Find<ServiceThrottlingBehavior>();

            if (throttle == null)
            {
                throttle = new ServiceThrottlingBehavior();
                _serviceHost.Description.Behaviors.Add(throttle);
            }

            throttle.MaxConcurrentCalls = 100;
            throttle.MaxConcurrentInstances = 100;
            throttle.MaxConcurrentSessions = 100;
        }
    }

    /// <summary>
    /// Client proxy factory for consuming the healthcare records service securely.
    /// </summary>
    public class HealthcareServiceClientFactory
    {
        /// <summary>
        /// Creates a secure WCF client channel to the healthcare records service.
        /// Uses the same strong encryption suite (Basic256Sha256) as the server.
        /// </summary>
        public static IHealthcareRecordsService CreateClient(
            string endpointAddress,
            string clientCertThumbprint,
            string serviceCertThumbprint)
        {
            var binding = SecureBindingFactory.CreateHipaaCompliantBinding();
            var endpointAddr = new EndpointAddress(
                new Uri(endpointAddress),
                EndpointIdentity.CreateX509CertificateIdentity(
                    FindCertificate(StoreLocation.LocalMachine, StoreName.TrustedPeople,
                        X509FindType.FindByThumbprint, serviceCertThumbprint)));

            var factory = new ChannelFactory<IHealthcareRecordsService>(binding, endpointAddr);

            // Set client certificate
            factory.Credentials.ClientCertificate.SetCertificate(
                StoreLocation.CurrentUser,
                StoreName.My,
                X509FindType.FindByThumbprint,
                clientCertThumbprint);

            // Validate server certificate
            factory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
                System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
            factory.Credentials.ServiceCertificate.Authentication.RevocationMode =
                X509RevocationMode.Online;

            return factory.CreateChannel();
        }

        private static X509Certificate2 FindCertificate(
            StoreLocation location, StoreName name,
            X509FindType findType, string findValue)
        {
            var store = new X509Store(name, location);
            try
            {
                store.Open(OpenFlags.ReadOnly);
                var certs = store.Certificates.Find(findType, findValue, true);
                if (certs.Count == 0)
                    throw new InvalidOperationException(
                        $"Certificate not found: {findValue}");
                return certs[0];
            }
            finally
            {
                store.Close();
            }
        }
    }

